import okhttp3.Interceptor
import okhttp3.Response

// Auth interceptor — adds bearer token, retries once on 401
class AuthInterceptor(
  private val tokens: TokenStore
) : Interceptor {
  override fun intercept(chain: Interceptor.Chain): Response {
    val original = chain.request()
    val withAuth = original.newBuilder()
      .addHeader("Authorization", "Bearer \${tokens.access ?: \"\"}")
      .build()
    val response = chain.proceed(withAuth)
    if (response.code != 401) return response
    response.close()
    val newToken = runBlocking { tokens.refresh() } ?: return chain.proceed(original)
    val retried = original.newBuilder()
      .addHeader("Authorization", "Bearer \$newToken")
      .build()
    return chain.proceed(retried)
  }
}

// Custom retry with exponential backoff (for transient failures)
class RetryInterceptor(private val maxAttempts: Int = 3) : Interceptor {
  override fun intercept(chain: Interceptor.Chain): Response {
    var attempt = 0
    var lastError: IOException? = null
    while (attempt < maxAttempts) {
      try {
        val r = chain.proceed(chain.request())
        if (r.code in 500..599) {
          r.close(); attempt++; Thread.sleep(200L * (1L shl attempt)); continue
        }
        return r
      } catch (e: IOException) {
        lastError = e; attempt++; Thread.sleep(200L * (1L shl attempt))
      }
    }
    throw lastError ?: IOException("retry exhausted")
  }
}

// Wire up
val client = OkHttpClient.Builder()
  .addInterceptor(HttpLoggingInterceptor().apply { level = HttpLoggingInterceptor.Level.HEADERS })
  .addInterceptor(AuthInterceptor(tokens))
  .addInterceptor(RetryInterceptor(maxAttempts = 3))
  .build()

import retrofit2.HttpException
import retrofit2.Response
import java.io.IOException

sealed class AppError(message: String? = null) : Throwable(message) {
  object NetworkUnavailable : AppError()
  data class Server(val code: Int, val payload: String?) : AppError("\$code")
  data class NotAuthorized(val cause: Throwable? = null) : AppError("401")
  data class Unknown(val cause: Throwable) : AppError(cause.message)
}

suspend fun <T> safeApi(block: suspend () -> T): Result<T> = try {
  Result.success(block())
} catch (e: HttpException) {
  val body = e.response()?.errorBody()?.string()
  val mapped = when (e.code()) {
    401 -> AppError.NotAuthorized(e)
    in 500..599 -> AppError.Server(e.code(), body)
    else -> AppError.Server(e.code(), body)
  }
  Result.failure(mapped)
} catch (e: IOException) {
  Result.failure(AppError.NetworkUnavailable)
} catch (e: Throwable) {
  Result.failure(AppError.Unknown(e))
}

// Repository
class UserRepository(private val api: UserApi) {
  suspend fun getUser(id: Long): Result<User> = safeApi {
    api.getUser(id).toDomain()
  }
}

// In ViewModel
val result = userRepository.getUser(id)
result.onSuccess { _state.update { it.copy(user = it) } }
