import okhttp3.Cache
import okhttp3.OkHttpClient
import okhttp3.Interceptor
import okhttp3.CacheControl
import java.util.concurrent.TimeUnit

val cacheDir = File(context.cacheDir, "http").apply { mkdirs() }
val cache = Cache(directory = cacheDir, maxSize = 50L * 1024 * 1024) // 50 MB

// Force a max-age header on responses (server doesn't always send useful Cache-Control)
val rewriteCache = Interceptor { chain ->
  val response = chain.proceed(chain.request())
  response.newBuilder()
    .header("Cache-Control", "public, max-age=300") // 5 minutes
    .removeHeader("Pragma")
    .build()
}

// Use cache when offline
val offlineFallback = Interceptor { chain ->
  val request = if (!isNetworkAvailable(context)) {
    chain.request().newBuilder()
      .cacheControl(CacheControl.Builder().onlyIfCached().maxStale(7, TimeUnit.DAYS).build())
      .build()
  } else chain.request()
  chain.proceed(request)
}

val client = OkHttpClient.Builder()
  .cache(cache)
  .addInterceptor(offlineFallback)        // app interceptor
  .addNetworkInterceptor(rewriteCache)    // network interceptor — once per network round trip
  .build()

