import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.WebSocket
import okhttp3.WebSocketListener

class ChatSocket(private val client: OkHttpClient) {
  private var socket: WebSocket? = null

  fun connect(url: String, onMessage: (String) -> Unit) {
    val request = Request.Builder().url(url).build()
    socket = client.newWebSocket(request, object : WebSocketListener() {
      override fun onMessage(webSocket: WebSocket, text: String) { onMessage(text) }
      override fun onClosing(ws: WebSocket, code: Int, reason: String) { ws.close(code, reason) }
      override fun onFailure(ws: WebSocket, t: Throwable, response: Response?) { /* reconnect */ }
    })
  }

  fun send(text: String) { socket?.send(text) }
  fun close() { socket?.close(1000, "bye"); socket = null }
}

// As a Flow
fun WebSocket.asFlow(): Flow<String> = callbackFlow {
  val listener = object : WebSocketListener() {
    override fun onMessage(ws: WebSocket, text: String) { trySend(text) }
    override fun onClosed(ws: WebSocket, code: Int, reason: String) { close() }
    override fun onFailure(ws: WebSocket, t: Throwable, r: Response?) { close(t) }
  }
  // assume socket already created with this listener
  awaitClose { /* close socket */ }
}
